  return value.replace(/[.*+?^${}()|[\]\\]/gu, "\\$&");
}

function formatStringList(values) {
  return values.map((value) => `"${value}"`).join(", ");
}

function stringArraysEqual(actual, expected) {
  return (
    Array.isArray(actual) &&
    actual.length === expected.length &&
    actual.every((value, index) => value === expected[index])
  );
}

function extractStringArrayFromBody(body) {
  const values = [];
  const stringPattern = /"([^"]+)"/gu;
  let match = stringPattern.exec(body);

  while (match) {
    values.push(match[1]);
    match = stringPattern.exec(body);
  }

  return values;
}

function extractExportedFrozenStringArray(text, exportName) {
  const arrayPattern = new RegExp(
    String.raw`export\s+const\s+${exportName}\s*=\s*Object\.freeze\(\s*\[([\s\S]*?)\]\s*\)`,
    "u"
  );
  const match = text.match(arrayPattern);

  return match ? extractStringArrayFromBody(match[1]) : null;
}

function extractAssertedStringArray(text, exportedName) {
  const arrayPattern = new RegExp(
    String.raw`assert\.deepEqual\(\s*${exportedName}\s*,\s*\[([\s\S]*?)\]\s*\)`,
    "u"
  );
  const match = text.match(arrayPattern);

  return match ? extractStringArrayFromBody(match[1]) : null;
}

function addExactStringArrayError(errors, label, actual, expected) {
  if (!stringArraysEqual(actual, expected)) {
    errors.push(
      `${label} must be exactly [${formatStringList(expected)}]`
    );
  }
}

function stripAllowedSourceMatches(text, relativePath, allowedMatches = {}) {
  const allowedSnippets = allowedMatches[relativePath] ?? [];
  let strippedText = text;

  for (const allowedSnippet of allowedSnippets) {
    strippedText = strippedText.split(allowedSnippet).join("");
  }

  return strippedText;
}

function stripSingleMarkedBlock(text, startToken, endToken) {
  const startIndex = text.indexOf(startToken);

  if (startIndex === -1) {
    return {
      found: false,
      malformed: false,
      text
    };
  }

  const endIndex = text.indexOf(endToken, startIndex + startToken.length);

  if (endIndex === -1) {
    return {
      found: true,
      malformed: true,
      text
    };
  }

  return {
    found: true,
    malformed: false,
    text: `${text.slice(0, startIndex)}${text.slice(endIndex + endToken.length)}`
  };
}

function stripK2009BoundedFilesystemInspectionCalls(text) {
  let strippedText = text;

  for (const pattern of K2009_DIRECT_BOUNDED_FILESYSTEM_CALL_PATTERNS) {
    strippedText = strippedText.replace(pattern, "");
  }

  return strippedText;
}

function skipQuotedLiteral(text, startIndex, quote) {
  let index = startIndex + 1;

  while (index < text.length) {
    if (text[index] === "\\") {
      index += 2;
      continue;
    }

    if (text[index] === quote) {
      return index + 1;
    }

    index += 1;
  }

  return index;
}

function copyBacktickLiteralContents(text, startIndex) {
  let copiedText = "`";
  let index = startIndex + 1;

  while (index < text.length) {
    const character = text[index];

    if (character === "\\") {
      copiedText += text.slice(index, index + 2);
      index += 2;
      continue;
    }

    copiedText += character;
    index += 1;

    if (character === "`") {
      return {
        text: copiedText,
        index
      };
    }
  }

  return {
    text: copiedText,
    index
  };
}

function copyLineCommentContents(text, startIndex) {
  let index = startIndex;

  while (index < text.length && text[index] !== "\n") {
    index += 1;
  }

  return {
    text: text.slice(startIndex, index),
    index
  };
}

function copyBlockCommentContents(text, startIndex) {
  const endIndex = text.indexOf("*/", startIndex + 2);
  const index = endIndex === -1 ? text.length : endIndex + 2;

  return {
    text: text.slice(startIndex, index),
    index
  };
}

function previousSignificantToken(text, startIndex) {
  let index = startIndex - 1;

  while (index >= 0 && /\s/u.test(text[index])) {
    index -= 1;
  }

  if (index < 0) {
    return "";
  }

  if (/[A-Za-z0-9_$]/u.test(text[index])) {
    const endIndex = index + 1;

    while (index >= 0 && /[A-Za-z0-9_$]/u.test(text[index])) {
      index -= 1;
    }

    return text.slice(index + 1, endIndex);
  }

  return text[index];
}

function isLikelyRegexLiteralStart(text, startIndex) {
  const previousToken = previousSignificantToken(text, startIndex);

  return (
    previousToken === "" ||
    /[([{=:,;!&|?+\-*~^<>]/u.test(previousToken) ||
    [
      "await",
      "case",
      "delete",
      "in",
      "instanceof",
      "return",
      "throw",
      "typeof",
      "void",
      "yield"
    ].includes(previousToken)
  );
}

function copyRegexLiteralContents(text, startIndex) {
  let copiedText = "/";
  let index = startIndex + 1;
  let inCharacterClass = false;

  while (index < text.length) {
    const character = text[index];

    if (character === "\n" || character === "\r") {
      return {
        text: "/",
        index: startIndex + 1
      };
    }

    if (character === "\\") {
      copiedText += text.slice(index, index + 2);
      index += 2;
      continue;
    }

    copiedText += character;
    index += 1;

    if (character === "[") {
      inCharacterClass = true;
      continue;
    }

    if (character === "]") {
      inCharacterClass = false;
      continue;
    }

    if (character === "/" && !inCharacterClass) {
      while (index < text.length && /[A-Za-z]/u.test(text[index])) {
        copiedText += text[index];
        index += 1;
      }

      return {
        text: copiedText,
        index
      };
    }
  }

  return {
    text: "/",
    index: startIndex + 1
  };
}

function stripSingleAndDoubleQuotedLiteralContents(text) {
  let strippedText = "";
  let index = 0;

  while (index < text.length) {
    const character = text[index];

    if (character === '"' || character === "'") {
      strippedText += `${character}${character}`;
      index = skipQuotedLiteral(text, index, character);
      continue;
    }

    if (character === "/" && text[index + 1] === "/") {
      const comment = copyLineCommentContents(text, index);
      strippedText += comment.text;
      index = comment.index;
      continue;
    }

    if (character === "/" && text[index + 1] === "*") {
      const comment = copyBlockCommentContents(text, index);
      strippedText += comment.text;
      index = comment.index;
      continue;
    }

    if (character === "/" && isLikelyRegexLiteralStart(text, index)) {
      const regex = copyRegexLiteralContents(text, index);
      strippedText += regex.text;
      index = regex.index;
      continue;
    }

    if (character === "`") {
      const template = copyBacktickLiteralContents(text, index);
      strippedText += template.text;
      index = template.index;
      continue;
    }

    strippedText += character;
    index += 1;
  }

  return strippedText;
}

function staleCandidateStagingVocabularyPattern(staleToken) {
  if (staleToken === ["recover", "y"].join("")) {
    return new RegExp(
      `["']${escapeRegExp(staleToken)}["']|candidate-staging:${escapeRegExp(
        staleToken
      )}:`,
      "u"
    );
  }

  return new RegExp(escapeRegExp(staleToken), "u");
}

function addStaleCandidateStagingVocabularyErrors(errors, label, text) {
  for (const staleToken of K2008_STALE_CANDIDATE_STAGING_VOCABULARY) {
    if (staleCandidateStagingVocabularyPattern(staleToken).test(text)) {
      errors.push(
        `${label} must not accept stale candidate staging vocabulary: ${staleToken}`
      );
    }
  }
}

function validateConfinedVocabularyGroup({ errors, resolvedRoot, relativePath, group }) {
  if (
    group.allowedFiles.includes(relativePath) ||
    !existsSync(join(resolvedRoot, relativePath))
  ) {
    return;
  }

  const text = group.stringLiteralExceptionFiles.includes(relativePath)
    ? stripSingleAndDoubleQuotedLiteralContents(readText(resolvedRoot, relativePath))
    : readText(resolvedRoot, relativePath);

  for (const token of group.vocabulary) {
    const tokenPattern = new RegExp(
      String.raw`(?:^|[^A-Za-z0-9_$])${escapeRegExp(token)}(?![A-Za-z0-9_$])`,
      "u"
    );

    if (tokenPattern.test(text)) {
      errors.addRule(
        group.ruleId,
        `${group.messagePrefix}: ${token} found in ${relativePath}`,
        {
          relativePath,
          token,
          lifecycle: group.lifecycle
        }
      );
    }
  }
}

function validateConfinedVocabularyGroups({ errors, resolvedRoot }) {
  for (const group of CONFINED_VOCABULARY_GROUPS) {
    for (const relativePath of REQUIRED_FILES) {
      validateConfinedVocabularyGroup({
        errors,
        resolvedRoot,
        relativePath,
        group
      });
    }
  }
}

function addDuplicateEntryErrors({
  values,
  getValue = (value) => value,
  ruleId,
  messagePrefix,
  addError
}) {
  const seen = new Set();

  for (const entry of values) {
    const value = getValue(entry);
    if (typeof value !== "string" || value.length === 0) {
      continue;
    }

    if (seen.has(value)) {
      addError(ruleId, `${messagePrefix}: ${value}`, { value });
      continue;
    }

    seen.add(value);
  }
}

export function validateValidatorConfiguration({
  requiredFiles = REQUIRED_FILES,
  governedFilesWithBoundaryMarkers = GOVERNED_FILES_WITH_BOUNDARY_MARKERS,
  governedFilesWithoutAuthorityFieldNames =
    GOVERNED_FILES_WITHOUT_AUTHORITY_FIELD_NAMES,
  forbiddenSourcePatterns = FORBIDDEN_SOURCE_PATTERNS,
  confinedVocabularyGroups = CONFINED_VOCABULARY_GROUPS,
  addError
} = {}) {
  addDuplicateEntryErrors({
    values: requiredFiles,
    ruleId: "K2-VALIDATOR-DUPLICATE-REQUIRED-FILE",
    messagePrefix: "Duplicate validator required file entry",
    addError
  });
  addDuplicateEntryErrors({
    values: governedFilesWithBoundaryMarkers,
    ruleId: "K2-VALIDATOR-DUPLICATE-GOVERNED-BOUNDARY-MARKER",
    messagePrefix: "Duplicate governed boundary marker file entry",
    addError
  });
  addDuplicateEntryErrors({
    values: governedFilesWithoutAuthorityFieldNames,
    ruleId: "K2-VALIDATOR-DUPLICATE-GOVERNED-AUTHORITY-FIELD-SCAN-FILE",
    messagePrefix: "Duplicate governed authority-field scan file entry",
    addError
  });
  addDuplicateEntryErrors({
    values: forbiddenSourcePatterns,
    getValue: (pattern) => pattern.id,
    ruleId: "K2-VALIDATOR-DUPLICATE-DENIED-SOURCE-PATTERN-ID",
    messagePrefix: "Duplicate denied source pattern ID",
    addError
  });
  addDuplicateEntryErrors({
    values: confinedVocabularyGroups,
    getValue: (group) => group.ruleId,
    ruleId: "K2-VALIDATOR-DUPLICATE-CONFINED-VOCABULARY-GROUP-ID",
    messagePrefix: "Duplicate confined vocabulary group rule ID",
    addError
  });
}

